package input

import (
	"context"
	"encoding/json"
	"sync"
	"time"

	"github.com/go-co-op/gocron/v2"
	"github.com/redpanda-data/benthos/v4/public/service"

	"github.com/openmeterio/openmeter/collector/benthos/services/leaderelection"
)

func myInputConfig() *service.ConfigSpec {
	return service.NewConfigSpec().Fields(
		service.NewStringField("schedule").Default("0 * * * * *"),
	)
}

func init() {
	err := service.RegisterBatchInput("my_input", myInputConfig(), func(conf *service.ParsedConfig, mgr *service.Resources) (service.BatchInput, error) {
		return newMyInput(conf, mgr)
	})
	if err != nil {
		panic(err)
	}
}

type myInput struct {
	resources *service.Resources
	scheduler gocron.Scheduler
	store     map[time.Time][]any
	mu        sync.Mutex
}

func newMyInput(conf *service.ParsedConfig, res *service.Resources) (*myInput, error) {
	schedule, _ := conf.FieldString("schedule")
	s, _ := gocron.NewScheduler()
	in := &myInput{resources: res, scheduler: s, store: make(map[time.Time][]any)}
	_ = schedule
	return in, nil
}

func (in *myInput) Connect(ctx context.Context) error {
	_, err := in.scheduler.NewJob(gocron.CronJob("0 * * * * *", true), gocron.NewTask(func(ctx context.Context) error {
		t := time.Now().UTC()
		in.mu.Lock()
		in.store[t] = []any{"item"}
		in.mu.Unlock()
		return nil
	}), gocron.WithContext(ctx))
	if err != nil {
		return err
	}
	go func() {
		running := false
		for {
			select {
			case <-ctx.Done():
				return
			case <-time.After(1 * time.Second):
				if leaderelection.IsLeader(in.resources) && !running {
					in.scheduler.Start(); running = true
				} else if !leaderelection.IsLeader(in.resources) && running {
					_ = in.scheduler.StopJobs(); running = false
				}
			}
		}
	}()
	return nil
}

func (in *myInput) ReadBatch(_ context.Context) (service.MessageBatch, service.AckFunc, error) {
	in.mu.Lock()
	defer in.mu.Unlock()
	if len(in.store) == 0 {
		return nil, func(context.Context, error) error { return nil }, nil
	}
	processing := make(map[time.Time][]any)
	var batch service.MessageBatch
	for t, items := range in.store {
		for _, item := range items {
			b, _ := json.Marshal(item)
			msg := service.NewMessage(b)
			msg.MetaSet("scrape_time", t.Format(time.RFC3339))
			batch = append(batch, msg)
		}
		processing[t] = items
		delete(in.store, t)
	}
	return batch, func(_ context.Context, err error) error {
		if err != nil {
			in.mu.Lock(); defer in.mu.Unlock()
			for t, v := range processing { in.store[t] = v }
		}
		return nil
	}, nil
}

func (in *myInput) Close(_ context.Context) error { return in.scheduler.Shutdown() }

